          site_name == o.site_name &&
          more_info == o.more_info &&
          bank_id == o.bank_id &&
          id == o.id &&
          meta == o.meta &&
          supported_languages == o.supported_languages &&
          supported_currencies == o.supported_currencies &&
          accessibility_features == o.accessibility_features &&
          address == o.address &&
          cash_withdrawal_national_fee == o.cash_withdrawal_national_fee &&
          friday == o.friday &&
          notes == o.notes &&
          is_accessible == o.is_accessible &&
          thursday == o.thursday &&
          saturday == o.saturday &&
          located_at == o.located_at &&
          minimum_withdrawal == o.minimum_withdrawal
    end

    # @see the `==` method
    # @param [Object] Object to be compared
    def eql?(o)
      self == o
    end

    # Calculates hash code according to all attributes.
    # @return [Integer] Hash code
    def hash
      [sunday, services, name, location, tuesday, cash_withdrawal_international_fee, wednesday, branch_identification, location_categories, site_identification, monday, has_deposit_capability, balance_inquiry_fee, site_name, more_info, bank_id, id, meta, supported_languages, supported_currencies, accessibility_features, address, cash_withdrawal_national_fee, friday, notes, is_accessible, thursday, saturday, located_at, minimum_withdrawal].hash
    end

    # Builds the object from hash
    # @param [Hash] attributes Model attributes in the form of hash
    # @return [Object] Returns the model itself
    def self.build_from_hash(attributes)
      return nil unless attributes.is_a?(Hash)
      attributes = attributes.transform_keys(&:to_sym)
      transformed_hash = {}
      openapi_types.each_pair do |key, type|
        if attributes.key?(attribute_map[key]) && attributes[attribute_map[key]].nil?
          transformed_hash["#{key}"] = nil
        elsif type =~ /\AArray<(.*)>/i
          # check to ensure the input is an array given that the attribute
          # is documented as an array but the input is not
          if attributes[attribute_map[key]].is_a?(Array)
            transformed_hash["#{key}"] = attributes[attribute_map[key]].map { |v| _deserialize($1, v) }
          end
        elsif !attributes[attribute_map[key]].nil?
          transformed_hash["#{key}"] = _deserialize(type, attributes[attribute_map[key]])
        end
      end
      new(transformed_hash)
    end

    # Returns the object in the form of hash
    # @return [Hash] Returns the object in the form of hash
    def to_hash
      hash = {}
      self.class.attribute_map.each_pair do |attr, param|
        value = self.send(attr)
        if value.nil?
          is_nullable = self.class.openapi_nullable.include?(attr)
          next if !is_nullable || (is_nullable && !instance_variable_defined?(:"@#{attr}"))
        end

        hash[param] = _to_hash(value)
      end
      hash
    end

  end

